INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6, 0, "あたしも教官の仕事を\n頑張れば、あいつに\n喜んでもらえたり\nするのかな…", 6006, 8, 0, 0, 11, 0.3, 1, 129811);
