INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6, 0, "マコトさん？\nどうかしましたか？\n何やら不穏な気配を\n感じ取ったのですが", 6011, 6, 0, 0, 11, 0.8, 1, 129911);
INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (6, "", "", 6012, "", "", "", 91, "", "", 0);
