INSERT INTO `v1_4db823afe21ee05670f1a76f597547ed6b350ee90d5821e555e19ce49c1027bf` VALUES (7, 0, "私の班のみなさんも\n変わらず訓練に励んで\nいるようですわね\n殊勝なことです", 7006, 6, 0, 0, 11, 0.3, 1, 129911);
